async function executeSendFiles(targetRepo, targetIsOrg) {
    const checked = Array.from(document.querySelectorAll('#file-list-container .file-check:checked')).map(c => c.value);
    if (!confirm(`🚀 Send ${checked.length} files to ${targetRepo}? Existing files will be overwritten.`)) return;

    closeRepoSelector();
    showGlobalToast("📦 Gathering files...");

    try {
        const operations = [{ action: 'comment', text: `[Inbound] Transfer from ${CONFIG.repoName}` }];

        for (const path of checked) {
            const res = await fetch(CONFIG.funcUrl, {
                method: 'POST', headers: { 'Content-Type': 'application/json' },
                body: apiBody({ action: 'preview_file', file_path: path })
            });
            const data = await res.json();
            if (data.content) {
                operations.push({
                    action: 'create_file',
                    file_path: path,
                    content: b64DecodeUnicode(data.content)
                });
            }
        }

        showGlobalToast(`📡 Uploading to ${targetRepo}...`);

        const sendRes = await fetch(CONFIG.funcUrl, {
            method: 'POST', headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                action: 'patch',
                repo_name: targetRepo,
                is_org: targetIsOrg,
                operations: operations,
                ai_config: window.aiConfig
            })
        });
        const sendData = await sendRes.json();

        if (sendData.success) {
            showGlobalToast("✅ Transfer Complete!", false);
        } else {
            throw new Error(sendData.error || "Upload failed");
        }
    } catch (e) {
        alert("Send Error: " + e.message);
    }
}

